// Fire manager_refreshed IMMEDIATELY — before service re-registration.
// This allows connectToServer's wm proxy to be updated as soon as
// possible, minimizing the window where stale methods exist.
this._fire("manager_refreshed", { manager });

const services = Object.values(this._services);
const servicesCount = services.length;
let registeredCount = 0;
const failedServices = [];

// Use timeout for service registration to prevent hanging
// _method_timeout is in seconds, withTimeout expects milliseconds
const serviceRegistrationTimeout = (this._method_timeout || 30) * 1000;

for (let service of services) {
  // Skip local-only services (e.g. _rintf_ callback proxies) —
  // they must never be registered with the server; doing so
  // creates zombie entries in Redis.
  if (service.config && service.config._local_only) {
    servicesCount--;
    continue;
  }
  try {
    const serviceInfo = this._extract_service_info(service);
    await withTimeout(
      manager.registerService(serviceInfo),
      serviceRegistrationTimeout,
      `Timeout registering service ${service.id || "unknown"}`,
    );

