            heartbeat["_renc_pub"] = caller_encryption_pub
            resolve["_renc_pub"] = caller_encryption_pub
            reject["_renc_pub"] = caller_encryption_pub
        return {
            "heartbeat": heartbeat,
            "resolve": resolve,
            "reject": reject,
            "interval": data["t"],
        }

