        const originalExtra = decoded[0];
        delete data._enc;
        delete data.data;
        Object.assign(data, originalExtra);
        // Store caller's encryption pub in context
        data.ctx.encryption = true;
        data.ctx.caller_public_key = publicKeyToHex(callerEncryptionPub);
