          else if (
            remote_workspace === "*" &&
            remote_client_id === this._connection.manager_id
          ) {
            // Access granted
          }
          // Allow _rintf callbacks from the specific client they were sent to
          else if (
            this._method_annotations.get(method).rintf_allowed_caller
