              this._method_annotations.get(method).rintf_allowed_caller;
            const caller = data.from || "";
            if (caller !== allowed) {
              throw new Error(
                "Permission denied for _rintf callback " +
                  method_name +
                  ", caller " +
                  caller +
                  " is not the allowed caller " +
                  allowed,
