  }).timeout(20000);

  it("should enforce strict callback lifecycle: callbacks invalid after function returns", async () => {
    // Connect server (provider)
    const server = await connectToServer({
      server_url: SERVER_URL,
      client_id: "lifecycle-provider",
    });
    const workspace = server.config.workspace;
    const token = await server.generateToken();

    let storedCallback = null;

    await server.registerService({
      name: "Lifecycle Service",
      id: "lifecycle-svc",
      config: { visibility: "protected" },
      use_callback_and_return: async (callback) => {
        // Callback should work during execution
        const result = await callback("during-execution");
        storedCallback = callback;
        return result;
      },
      invoke_stored_callback: async () => {
        if (!storedCallback) throw new Error("No stored callback");
        // This should fail because the session was cleaned up
        const result = await storedCallback("after-return");
        return result;
      },
    });

    // Connect client (consumer)
    const client = await connectToServer({
      server_url: SERVER_URL,
      client_id: "lifecycle-consumer",
      workspace: workspace,
      token: token,
    });

    const svc = await client.getService("lifecycle-svc");

    // 1. Callback works DURING execution
    const callbackInvocations = [];
    const result = await svc.use_callback_and_return((msg) => {
      callbackInvocations.push(msg);
      return `reply-${msg}`;
    });
    expect(result).to.equal("reply-during-execution");
    expect(callbackInvocations).to.deep.equal(["during-execution"]);

    // 2. Session should be cleaned up after function returned
    // Wait briefly for cleanup propagation
    await new Promise((r) => setTimeout(r, 500));

    // 3. Server tries to invoke the stored callback — should fail
    // because the client cleaned up the session when the function returned
    let invokeError = null;
    try {
      await svc.invoke_stored_callback();
    } catch (e) {
      invokeError = e;
    }
    expect(invokeError).to.not.be.null;

    await client.disconnect();
    await server.disconnect();
  }).timeout(30000);

  it("should keep _rintf callbacks alive after function returns and allow manual cleanup", async () => {
    const server = await connectToServer({
      server_url: SERVER_URL,
      client_id: "rintf-provider",
    });
    const workspace = server.config.workspace;
    const token = await server.generateToken();

    let storedInterface = null;

    await server.registerService({
      name: "RIntf Service",
      id: "rintf-svc",
      config: { visibility: "protected" },
      use_interface_and_return: async (interfaceObj) => {
        // Call getItem during execution — should work
        const result = await interfaceObj.getItem("key1");
        storedInterface = interfaceObj;
        return result;
      },
      call_stored_interface: async (key) => {
        if (!storedInterface) throw new Error("No stored interface");
        return await storedInterface.getItem(key);
      },
    });

    const client = await connectToServer({
      server_url: SERVER_URL,
      client_id: "rintf-consumer",
      workspace: workspace,
      token: token,
    });

    const svc = await client.getService("rintf-svc");

    // Create an interface object with _rintf: true
    const dataStore = { key1: "value1", key2: "value2" };
    const interfaceObj = {
      _rintf: true,
      getItem: (key) => dataStore[key] || null,
    };

    // Verify no _rintf services exist before the call
    const rintfServicesBefore = Object.keys(client.rpc._services).filter(
      (k) => k.startsWith("_rintf_")
    );
    expect(rintfServicesBefore.length).to.equal(0);

    // 1. Call with _rintf interface — callback works during execution
    const result = await svc.use_interface_and_return(interfaceObj);
    expect(result).to.equal("value1");

    // Verify _rintf_service_id was set back on the original object
    expect(interfaceObj._rintf_service_id).to.be.a("string");
    expect(interfaceObj._rintf_service_id).to.match(/^_rintf_/);
    const rintfServiceId = interfaceObj._rintf_service_id;

    // Verify the _rintf service was auto-registered on the client side
    expect(client.rpc._services[rintfServiceId]).to.not.be.undefined;

    // 2. Callback still works AFTER function returned (because _rintf persists)
    await new Promise((r) => setTimeout(r, 500));
    const result2 = await svc.call_stored_interface("key2");
    expect(result2).to.equal("value2");

    // 3. Service persists — no auto-timeout
    await new Promise((r) => setTimeout(r, 2000));
    expect(client.rpc._services[rintfServiceId]).to.not.be.undefined;
    const result3 = await svc.call_stored_interface("key1");
    expect(result3).to.equal("value1");

    // 4. Manual unregistration works (auto-detects _rintf as local-only)
    await client.rpc.unregister_service(rintfServiceId);

    // Service should now be gone
    expect(client.rpc._services[rintfServiceId]).to.be.undefined;

    // Calling the stored interface should fail
    let cleanupError = null;
    try {
      await svc.call_stored_interface("key1");
    } catch (e) {
      cleanupError = e;
    }
    expect(cleanupError).to.not.be.null;

    await client.disconnect();
    await server.disconnect();
  }).timeout(30000);

  it("should call _dispose on _rintf services when their allowed caller disconnects", async () => {
    const server = await connectToServer({
      server_url: SERVER_URL,
      client_id: "rintf-dispose-provider",
    });
    const workspace = server.config.workspace;
    const token = await server.generateToken();

    await server.registerService({
      name: "RIntf Dispose Service",
      id: "rintf-dispose-svc",
      config: { visibility: "protected" },
      register_listener: async (interfaceObj) => {
        return "registered";
      },
    });

    const client = await connectToServer({
      server_url: SERVER_URL,
      client_id: "rintf-dispose-consumer",
      workspace: workspace,
      token: token,
    });

    const svc = await client.getService("rintf-dispose-svc");

    const listenerObj = {
      _rintf: true,
      onUpdate: (data) => data,
    };

    await svc.register_listener(listenerObj);
    const rintfServiceId = listenerObj._rintf_service_id;
    expect(rintfServiceId).to.match(/^_rintf_/);

    const rintfSvc = client.rpc._services[rintfServiceId];
    expect(rintfSvc).to.not.be.undefined;

    // Spy on the _dispose method to verify it is called during cleanup
    let disposeWasCalled = false;
    const originalDispose = rintfSvc._dispose;
    rintfSvc._dispose = () => {
      disposeWasCalled = true;
      if (typeof originalDispose === "function") {
        originalDispose();
      }
    };

    // Disconnect the server (allowed caller) so _cleanupRintfForCaller fires on client
    await server.disconnect();

    // Give the client time to process the disconnect and clean up
    await new Promise((r) => setTimeout(r, 1000));

    // _dispose should have been called during cleanup
    expect(disposeWasCalled).to.be.true;
    // The _rintf service should have been removed
    expect(client.rpc._services[rintfServiceId]).to.be.undefined;

    await client.disconnect();
  }).timeout(30000);
});

describe("E2E Encrypted Service Calls", () => {
  it("should encrypt and decrypt RPC calls", async function () {
    this.timeout(30000);

    // Service provider with encryption
    const server = await connectToServer({
      server_url: SERVER_URL,
      client_id: "js-enc-server",
      encryption: true,
    });
    const workspace = server.config.workspace;
    const token = await server.generateToken();

    const receivedContexts = [];

    await server.registerService({
      id: "encrypted-svc",
      config: {
        require_context: true,
        visibility: "protected",
      },
      echo: (msg, context) => {
        receivedContexts.push(context);
        return `encrypted: ${msg}`;
      },
      add: (a, b, context) => {
        receivedContexts.push(context);
        return a + b;
      },
    });

    // Caller with encryption, same workspace
    const client = await connectToServer({
      server_url: SERVER_URL,
      client_id: "js-enc-caller",
      workspace: workspace,
      token: token,
      encryption: true,
    });

    // Caller provides server's public key out-of-band (not via server)
    const serverPubKey = server.rpc.getPublicKey();
    const svc = await client.getService("encrypted-svc", {
      encryption_public_key: serverPubKey,
    });

    // Encrypted call should succeed
    const result = await svc.echo("hello encrypted");
    expect(result).to.equal("encrypted: hello encrypted");

    // Context should have encryption info
    expect(receivedContexts.length).to.be.greaterThan(0);
    const ctx = receivedContexts[0];
    expect(ctx.encryption).to.be.true;
    expect(ctx.caller_public_key).to.be.a("string");
    expect(ctx.caller_public_key).to.have.lengthOf(64);

    // Another call
    const addResult = await svc.add(10, 20);
    expect(addResult).to.equal(30);

    // Consistent public key across calls
    expect(receivedContexts[1].caller_public_key).to.equal(
      receivedContexts[0].caller_public_key,
    );

    // Caller's key should match
    expect(receivedContexts[0].caller_public_key).to.equal(
      client.rpc.getPublicKey(),
    );

    console.log("✓ E2E encrypted service calls working");

    await client.disconnect();
    await server.disconnect();
  });

  it("should work with mixed encrypted and unencrypted clients", async function () {
    this.timeout(30000);

    const server = await connectToServer({
      server_url: SERVER_URL,
      client_id: "js-enc-optional-server",
      encryption: true,
    });
    const workspace = server.config.workspace;
    const token = await server.generateToken();

    const contexts = [];

    await server.registerService({
      id: "enc-optional-svc",
      config: {
        require_context: true,
        visibility: "protected",
      },
      echo: (msg, context) => {
        contexts.push(context);
        return `echo: ${msg}`;
      },
    });

    // Encrypted client, same workspace
    const encClient = await connectToServer({
      server_url: SERVER_URL,
      client_id: "js-enc-optional",
      workspace: workspace,
      token: token,
      encryption: true,
    });

    // Unencrypted client, same workspace
    const plainClient = await connectToServer({
      server_url: SERVER_URL,
      client_id: "js-plain-optional",
      workspace: workspace,
      token: token,
    });

    // Encrypted client provides server's public key out-of-band
    const serverPubKey = server.rpc.getPublicKey();
    const svcEnc = await encClient.getService("enc-optional-svc", {
      encryption_public_key: serverPubKey,
    });
    // Plain client does NOT provide encryption key
    const svcPlain = await plainClient.getService("enc-optional-svc");

    // Both should succeed
    const r1 = await svcEnc.echo("encrypted");
    expect(r1).to.equal("echo: encrypted");
    expect(contexts[contexts.length - 1].encryption).to.be.true;

    const r2 = await svcPlain.echo("plain");
    expect(r2).to.equal("echo: plain");
    // Unencrypted calls should not have encryption flag
    expect(contexts[contexts.length - 1].encryption).to.be.undefined;

    console.log("✓ Mixed encryption works correctly");

    await encClient.disconnect();
    await plainClient.disconnect();
    await server.disconnect();
  });
});

